module.exports = /*#__PURE__*/JSON.parse('{"page_title":"X Save: Stahovač videí z Twitteru v HD | Převodník z X na MP4","download":"Stáhnout","faq":"Časté dotazy","about":"O nás","home":"Domů","more":"Více","all_rights_reserved":"Všechna práva vyhrazena.","oops":"Jejda!","privacy_policy":"Zásady ochrany osobních údajů","disclaimer_page_title":"Vyloučení odpovědnosti","contact_us":"Kontaktujte nás","footer_disclaimer_short":"XSave nehostuje žádná videa, obrázky ani GIFy. Veškerý obsah patří jejich příslušným vlastníkům. Nejsme spojeni s Twitterem/X.","footer_site_description":"Stahujte videa a GIFy z Twitteru/X okamžitě — rychle, zdarma a bezpečně.","footer_nav_product":"Produkt","footer_nav_company":"Společnost","footer_nav_legal":"Právní","twitter_video_downloader":"Stahovač videí z X Twitter","paste_url_prompt":"Vložte níže URL jakéhokoli videa nebo GIFu z Twitteru/X a vygenerujte okamžité odkazy ke stažení.","enter_url_placeholder":"https://x.com/uzivatelskejmeno/status/...","error_enter_url":"Zadejte prosím URL z Twitteru/X.","error_invalid_url":"Byla zadána neplatná URL z Twitteru/X. Zkontrolujte prosím odkaz a zkuste to znovu.","error_private_video":"Toto video je soukromé, bylo smazáno nebo pochází z účtu, ke kterému nemáte přístup.","error_bad_response":"Nepodařilo se získat data o videu. Tweet možná neobsahuje video nebo došlo k chybě serveru.","error_generic":"Došlo k neznámé chybě. Zkontrolujte prosím připojení a zkuste to znovu.","error_paste_failed":"Nelze číst ze schránky.","paste_from_clipboard":"Vložit ze schránky","clear_input":"Vymazat vstup","xsave_title":"X Save: Stahovač videí z Twitteru","xsave_description_1":"XSave.app je nástroj pro stahování videí z Twitteru; je rychlý, bezpečný a spolehlivý. Pomocí našeho nástroje si můžete uložit virální meme, novinku nebo jakékoli video, GIF atd. Nejlepší na XSave je, že se nemusíte registrovat, abyste ho mohli používat; stačí vložit odkaz a stáhnout si videa z Twitteru v HD.","xsave_description_2":"Náš nástroj je vytvořen s ohledem na uživatelský zážitek; není třeba instalovat žádné rozšíření prohlížeče ani software. Jakmile vložíte URL jakéhokoli videa z Twitteru/X, náš výkonný backendový systém načte všechny dostupné kvality videa, které si můžete stáhnout jedním kliknutím.","how_to_title":"Jak stahovat videa z Twitteru/X pomocí XSave?","how_to_use_nav":"Jak používat","how_to_step_1":"Nejprve přejděte na Twitter/X a najděte video/GIF, které chcete stáhnout.","how_to_step_2":"Nyní klikněte na tlačítko sdílení a zkopírujte URL videa.","how_to_step_3":"Otevřete jakýkoli webový prohlížeč na svém zařízení, do adresního řádku zadejte xsave.app a stisknutím klávesy Enter navštivte stránku.","how_to_step_4":"Vložte odkaz na video z Twitteru do XSave a stiskněte tlačítko pro stažení, abyste načetli všechny dostupné kvality videa.","how_to_step_5":"Klepnutím na preferovanou kvalitu videa zahájíte stahování.","features_title":"Funkce stahovače videí X","feature_1":"🚀 <strong>Rychle a snadno</strong> – Vložte odkaz na tweet, klepněte na stáhnout a během několika sekund bude video staženo.","feature_2":"🎥 <strong>HD kvalita</strong> – Náš systém načte všechna dostupná rozlišení; můžete si vybrat od HD po různá další.","feature_3":"🔒 <strong>Bezpečně a soukromě</strong> – XSave.app nevyžaduje přihlášení ani skryté triky a je bez malwaru.","feature_4":"🌐 <strong>Funguje kdekoli</strong> – Náš nástroj můžete používat na jakékoli platformě s přístupem k internetu, ať už je to stolní počítač, tablet nebo mobil.","faq_title":"Často kladené otázky","faq_q1":"Jak používat stahovač videí z Twitteru/X?","faq_a1":"Zkopírujte URL tweetu obsahujícího video nebo GIF, vložte jej do pole na XSave.app a klepněte na tlačítko pro stažení.","faq_q2":"Je tato služba zdarma?","faq_a2":"Ano, X Save je zcela zdarma. Nejsou zde žádné skryté poplatky ani předplatné. Můžete si stáhnout tolik videí, kolik chcete.","faq_q3":"Mohu stahovat videa ze soukromých účtů?","faq_a3":"Ne, Xsave.app přistupuje pouze k veřejnému obsahu; respektujeme soukromí uživatelů a neobcházíme nastavení soukromí X.","faq_q4":"Jakou kvalitu videa mohu stáhnout?","faq_a4":"Kvalita videa závisí na původním videu nahraném na Twitter/X. Náš nástroj načte všechny dostupné kvality, jako je SD a HD, a můžete si vybrat podle svých potřeb.","faq_q5":"Je legální stahovat videa z Twitteru?","faq_a5":"Stahování videí je obecně určeno pouze pro vaše osobní použití. Prosím, nepoužívejte video znovu bez svolení vlastníka. Také se ujistěte, že znáte autorské zákony vaší země.","faq_q6":"Proč používat XSave.app pro převod z Twitteru na MP4?","faq_a6":"XSave je nejlepší nástroj pro stahování videí z Twitteru/X, protože je rychlý, bezplatný, bezpečný a nevyžaduje registraci.","about_title":"O XSave","about_p1":"XSave bylo vytvořeno z jednoduchého důvodu: někdy na Twitteru/X najdete video nebo GIF, které nechcete ztratit. Možná je to vtipné meme, zpravodajský klip nebo něco, co chcete sdílet později. S XSave si to můžete uložit několika kliknutími.","about_p2":"Udrželi jsme to jednoduché – žádné registrace, vyskakovací okna ani software k instalaci. Zkopírujte odkaz na tweet, vložte jej na naši stránku a stáhněte si video v kvalitě, která se vám líbí.","about_p3":"V zákulisí XSave používá důvěryhodné open-source nástroje k získání videa přímo z Twitteru/X. Neukládáme vaše soubory, nezaznamenáváme, co stahujete, a nehostujeme žádná média na našich serverech.","about_why_title":"Proč používat XSave?","about_why_feature_1":"<strong>Navždy zdarma.</strong> Žádné skryté poplatky ani omezení.","about_why_feature_2":"<strong>Rychlé a jednoduché.</strong> Zkopírovat, vložit, stáhnout.","about_why_feature_3":"<strong>Funguje kdekoli.</strong> Mobil, tablet nebo stolní počítač.","about_note_title":"Poznámka","about_note_p1":"XSave není spojen s Twitterem ani X Corp. Všechna práva zůstávají původním tvůrcům. Používejte prosím nástroj zodpovědně a dodržujte autorské zákony.","privacy_title":"Zásady ochrany osobních údajů pro XSave","privacy_intro":"V XSave, přístupném z xsave.app, je jednou z našich hlavních priorit soukromí našich návštěvníků. Tento dokument o zásadách ochrany osobních údajů obsahuje typy informací, které XSave shromažďuje a zaznamenává, a jak je používáme.","privacy_info_we_collect_title":"Informace, které shromažďujeme","privacy_info_we_collect_p1":"Nepožadujeme, aby se uživatelé registrovali k účtu nebo poskytovali jakékoli osobní údaje k používání naší služby. Jedinou informací, kterou zpracováváme, je URL z Twitteru/X, kterou zadáte do vstupního pole. Tyto URL neukládáme po zpracování požadavku.","privacy_log_files_title":"Soubory protokolu","privacy_log_files_p1":"XSave dodržuje standardní postup používání souborů protokolu. Tyto soubory zaznamenávají návštěvníky, když navštíví webové stránky. Informace shromážděné soubory protokolu zahrnují adresy internetového protokolu (IP), typ prohlížeče, datum a časové razítko a odkazující/výstupní stránky. Tyto údaje nejsou spojeny s žádnými informacemi, které by byly osobně identifikovatelné. Účelem těchto informací je analýza trendů, správa stránek a shromažďování demografických informací pro interní použití za účelem zlepšení našich služeb.","privacy_cookies_title":"Cookies a webové majáky","privacy_cookies_p1":"Stejně jako jakákoli jiná webová stránka, i XSave používá „cookies“. Tyto cookies se používají k ukládání informací včetně preferencí návštěvníků, jako jsou nastavení jazyka a motivu. Informace se používají k optimalizaci uživatelského zážitku přizpůsobením obsahu naší webové stránky na základě typu prohlížeče návštěvníků a/nebo dalších informací.","privacy_third_party_title":"Služby třetích stran","privacy_third_party_p1":"Nepoužíváme žádné služby třetích stran, které by shromažďovaly osobní údaje od našich uživatelů. Můžeme používat analytické služby, které shromažďují anonymní údaje o používání.","privacy_your_rights_title":"Vaše práva na ochranu údajů","privacy_your_rights_p1":"Jelikož neshromažďujeme osobní údaje, mnoho standardních práv na ochranu údajů se v běžném kontextu nemusí vztahovat. Jsme však odhodláni chránit soukromí uživatelů. Máte-li jakékoli dotazy nebo obavy týkající se vašeho soukromí při používání naší služby, kontaktujte nás.","privacy_consent_title":"Souhlas","privacy_consent_p1":"Používáním našich webových stránek souhlasíte s našimi zásadami ochrany osobních údajů a jejich podmínkami.","disclaimer_intro":"Informace poskytované společností XSave na xsave.app jsou určeny pouze pro obecné informační a osobní účely. Všechny informace na stránkách jsou poskytovány v dobré víře, nicméně neposkytujeme žádné prohlášení ani záruku jakéhokoli druhu, výslovnou ani implicitní, týkající se přesnosti, přiměřenosti, platnosti, spolehlivosti, dostupnosti nebo úplnosti jakýchkoli informací na stránkách.","disclaimer_accuracy_title":"Přesnost obsahu","disclaimer_accuracy_p1":"I když se snažíme poskytovat spolehlivou službu, nezaručujeme přesnost ani dostupnost odkazů na stahování videí. Funkčnost služby závisí na stálé dostupnosti obsahu Twitteru/X.","disclaimer_external_links_title":"Vyloučení odpovědnosti za externí odkazy","disclaimer_external_links_p1":"Stránky mohou obsahovat odkazy na jiné webové stránky nebo obsah patřící třetím stranám nebo z nich pocházející. Takové externí odkazy nejsou námi prošetřovány, monitorovány ani kontrolovány z hlediska přesnosti, přiměřenosti, platnosti, spolehlivosti, dostupnosti nebo úplnosti.","disclaimer_personal_responsibility_title":"Osobní odpovědnost","disclaimer_personal_responsibility_p1":"Jste výhradně odpovědní za jakýkoli obsah, který si stáhnete prostřednictvím naší služby. Je vaší odpovědností zajistit, abyste neporušovali žádné autorské zákony ani podmínky služby Twitteru/X. XSave nenese odpovědnost za jakékoli zneužití této služby.","disclaimer_no_affiliation_title":"Žádné spojení","disclaimer_no_affiliation_p1":"XSave je nezávislý projekt a není přidružen, spojen, autorizován, podporován ani žádným způsobem oficiálně spojen s X Corp (dříve Twitter, Inc.) ani s žádnou z jejích dceřiných společností nebo přidružených společností.","contact_title":"Kontaktujte nás","contact_intro":"Máte dotaz, návrh nebo zpětnou vazbu? Rádi bychom od vás slyšeli! Vyplňte prosím níže uvedený formulář a my se vám co nejdříve ozveme.","contact_form_name_label":"Vaše jméno","contact_form_name_placeholder":"Zadejte své jméno","contact_form_email_label":"Váš e-mail","contact_form_email_placeholder":"Zadejte svou e-mailovou adresu","contact_form_message_label":"Vaše zpráva","contact_form_message_placeholder":"Sem napište svou zprávu...","contact_form_submit_button":"Odeslat zprávu","contact_form_submitting_button":"Odesílání...","contact_form_success_message_title":"Zpráva odeslána!","contact_form_success_message_body":"Děkujeme, že jste nás kontaktovali. Obdrželi jsme vaši zprávu a brzy se vám ozveme.","contact_form_error_name":"Zadejte prosím své jméno.","contact_form_error_email":"Zadejte prosím platnou e-mailovou adresu.","contact_form_error_message":"Zadejte prosím zprávu.","contact_prompt":"Pokud potřebujete další informace nebo máte nějaké dotazy, neváhejte nás kontaktovat e-mailem na adrese <a href=\\"mailto:support@xsave.app\\">support@xsave.app</a>","download_another_video":"Stáhnout další video","not_found_title":"Stránka nenalezena","not_found_description":"Omlouváme se, stránka, kterou hledáte, neexistuje nebo byla přesunuta.","go_back_home":"Zpět na domovskou stránku","error_page_title_400":"Špatný požadavek","error_page_description_400":"Server nemohl porozumět požadavku kvůli neplatné syntaxi.","error_page_title_500":"Chyba serveru","error_page_description_500":"Vyskytly se technické potíže. Zkuste to prosím později.","error_page_title_generic":"Došlo k chybě","error_page_description_generic":"Něco se pokazilo. Zkuste prosím obnovit stránku nebo se vrátit později."}');

